VOID SafeDpcRoutine(
    _In_     PKDPC  Dpc,
    _In_opt_ PVOID  DeferredContext,
    _In_opt_ PVOID  SystemArgument1,
    _In_opt_ PVOID  SystemArgument2
) {
    PDEVICE_OBJECT devObj = (PDEVICE_OBJECT)DeferredContext;
    PDPC_WORK_ITEM ctx;
    UNREFERENCED_PARAMETER(Dpc);
    UNREFERENCED_PARAMETER(SystemArgument1);
    UNREFERENCED_PARAMETER(SystemArgument2);
    ctx = (PDPC_WORK_ITEM)ExAllocatePool2(POOL_FLAG_NON_PAGED, sizeof(DPC_WORK_ITEM), 'kwI ');
    if (!ctx) return;
    ctx->WorkItem = IoAllocateWorkItem(devObj);
    if (!ctx->WorkItem) { ExFreePoolWithTag(ctx, 'kwI '); return; }
    IoQueueWorkItem(ctx->WorkItem, SafeWorkItemCallback, DelayedWorkQueue, ctx);
}
